/**
 * Roll a stress die
 * 
 */

const tokens = canvas.tokens.controlled;

if (tokens.length == 1 ){
  rollStressDie(tokens[0]);
} else {
  printMessage("No Tokens were selected");
}

async function rollStressDie(token){
  let actor = token.actor;

  let dataset = {
    roll: "option",
    usefatigue :"false"
  };
  await actor.sheet.roll(dataset);

}


function printMessage(message){
  let chatData = {
    user : game.user._id,
    content : message,
    blind: true,
    whisper : game.users.filter(u => u.isGM).map(u => u.id)
  };
  ChatMessage.create(chatData,{});    
}
